1â†’import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
2â†’import { X, Palette, Link2, Trash2, Type, Plus, Minus, Save, FileDown, Grid3X3, AlignLeft, AlignCenter, AlignRight, Expand, Shrink } from 'lucide-react';
3â†’
4â†’const COLORS = [
5â†’  '#ff3131', '#ff6b35', '#ffea00', '#39ff14', '#00d2ff', '#a855f7', '#ec4899',
6â†’  '#ffffff', '#94a3b8', '#1e293b', '#000000', '#7c3aed', '#06b6d4', '#84cc16',
7â†’];
8â†’
9â†’const CELL_COLORS = [
10â†’  { label: 'Qizil', value: 'rgba(255,49,49,0.25)' },
11â†’  { label: 'Yashil', value: 'rgba(57,255,20,0.2)' },
12â†’  { label: 'Ko\'k', value: 'rgba(0,210,255,0.2)' },
13â†’  { label: 'Sariq', value: 'rgba(255,234,0,0.2)' },
14â†’  { label: 'Binafsha', value: 'rgba(168,85,247,0.2)' },
15â†’  { label: 'Pushti', value: 'rgba(236,72,153,0.2)' },
16â†’  { label: 'Tozalash', value: 'transparent' },
17â†’];
18â†’
19â†’const FONTS = ['Inter', 'Arial', 'Georgia', 'Courier New', 'Times New Roman'];
20â†’const SIZES = [10, 12, 14, 16, 18, 20, 24, 28, 32];
21â†’
22â†’const DEFAULT_ROWS = 30;
23â†’const DEFAULT_COLS = 12;
24â†’const COL_LABELS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
25â†’
26â†’function colLabel(c) {
27â†’  if (c < 26) return COL_LABELS[c];
28â†’  return COL_LABELS[Math.floor(c / 26) - 1] + COL_LABELS[c % 26];
29â†’}
30â†’
31â†’function cellKey(r, c) {
32â†’  return `${r}-${c}`;
33â†’}
34â†’
35â†’const ExcelTable = ({ initialData, onSave, machines = [] }) => {
36â†’  const [rows, setRows] = useState(initialData?.rows || DEFAULT_ROWS);
37â†’  const [cols, setCols] = useState(initialData?.cols || DEFAULT_COLS);
38â†’  const [cells, setCells] = useState(initialData?.cells || {});
39â†’  const [selectedCell, setSelectedCell] = useState(null);
40â†’  const [selectedRange, setSelectedRange] = useState(null);
41â†’  const [selectionStart, setSelectionStart] = useState(null);
42â†’  const [selecting, setSelecting] = useState(false);
43â†’  const [contextMenu, setContextMenu] = useState(null);
44â†’  const [editMode, setEditMode] = useState(false);
45â†’  const [editValue, setEditValue] = useState('');
46â†’  const [activePanel, setActivePanel] = useState(null);
47â†’  const [title, setTitle] = useState(initialData?.title || 'Yangi Hisobot');
48â†’  const [colWidths, setColWidths] = useState(() => {
49â†’    const saved = initialData?.colWidths;
50â†’    return saved || {};
51â†’  });
52â†’  const [rowHeights, setRowHeights] = useState(() => {
53â†’    const saved = initialData?.rowHeights;
54â†’    return saved || {};
55â†’  });
56â†’  const [autoResize, setAutoResize] = useState(false);
57â†’  const [resizing, setResizing] = useState(null);
58â†’  const [resizeStart, setResizeStart] = useState(null);
59â†’  const tableRef = useRef(null);
60â†’  const editRef = useRef(null);
61â†’  const measureRef = useRef(null);
62â†’
63â†’  const getCell = useCallback((r, c) => {
64â†’    return cells[cellKey(r, c)] || { value: '', style: {} };
65â†’  }, [cells]);
66â†’
67â†’  const updateCell = useCallback((r, c, updates) => {
68â†’    setCells(prev => {
69â†’      const key = cellKey(r, c);
70â†’      const existing = prev[key] || { value: '', style: {} };
71â†’      return { ...prev, [key]: { ...existing, ...updates } };
72â†’    });
73â†’  }, []);
74â†’
75â†’  // Measure text width using canvas
76â†’  const measureText = useCallback((text, fontSize = 13, fontFamily = 'Inter', fontWeight = 400) => {
77â†’    if (!measureRef.current) {
78â†’      measureRef.current = document.createElement('canvas').getContext('2d');
79â†’    }
80â†’    const ctx = measureRef.current;
81â†’    ctx.font = `${fontWeight === 700 ? 'bold ' : ''}${fontSize}px ${fontFamily}`;
82â†’    return ctx.measureText(text).width;
83â†’  }, []);
84â†’
85â†’  // Auto-resize column based on content
86â†’  const autoResizeColumn = useCallback((colIdx) => {
87â†’    let maxWidth = 40;
88â†’    for (let r = 0; r < rows; r++) {
89â†’      const cell = getCell(r, colIdx);
90â†’      const val = String(cell.value || '');
91â†’      if (!val) continue;
92â†’      const fontSize = cell.style?.fontSize || 13;
93â†’      const fontWeight = cell.style?.fontWeight || 400;
94â†’      const fontFamily = cell.style?.fontFamily || 'Inter';
95â†’      const lines = val.split('\n');
96â†’      for (const line of lines) {
97â†’        const w = measureText(line, fontSize, fontFamily, fontWeight);
98â†’        maxWidth = Math.max(maxWidth, w + 16);
99â†’      }
100â†’    }
101â†’    setColWidths(prev => ({ ...prev, [colIdx]: Math.ceil(maxWidth) }));
102â†’  }, [rows, getCell, measureText]);
103â†’
104â†’  // Auto-resize row based on content
105â†’  const autoResizeRow = useCallback((rowIdx) => {
106â†’    let maxHeight = 36;
107â†’    for (let c = 0; c < cols; c++) {
108â†’      const cell = getCell(rowIdx, c);
109â†’      const val = String(cell.value || '');
110â†’      if (!val) continue;
111â†’      const fontSize = cell.style?.fontSize || 13;
112â†’      const lines = val.split('\n');
113â†’      const cellWidth = colWidths[c] || 80;
114â†’      let totalLines = 0;
115â†’      for (const line of lines) {
116â†’        const w = measureText(line, fontSize, cell.style?.fontFamily || 'Inter', cell.style?.fontWeight || 400);
117â†’        totalLines += Math.max(1, Math.ceil(w / (cellWidth - 12)));
118â†’      }
119â†’      const h = totalLines * (fontSize + 4) + 16;
120â†’      maxHeight = Math.max(maxHeight, h);
121â†’    }
122â†’    setRowHeights(prev => ({ ...prev, [rowIdx]: Math.ceil(maxHeight) }));
123â†’  }, [cols, getCell, colWidths, measureText]);
124â†’
125â†’  // Auto-resize all
126â†’  const autoResizeAll = useCallback(() => {
127â†’    for (let c = 0; c < cols; c++) autoResizeColumn(c);
128â†’    for (let r = 0; r < rows; r++) autoResizeRow(r);
129â†’  }, [cols, rows, autoResizeColumn, autoResizeRow]);
130â†’
131â†’  // When auto-resize is on and cells change, resize all
132â†’  useEffect(() => {
133â†’    if (autoResize) {
134â†’      autoResizeAll();
135â†’    }
136â†’  }, [cells, autoResize, autoResizeAll]);
137â†’
138â†’  const getSelectedCells = useCallback(() => {
139â†’    if (selectedRange) {
140â†’      const res = [];
141â†’      const r1 = Math.min(selectedRange.r1, selectedRange.r2);
142â†’      const r2 = Math.max(selectedRange.r1, selectedRange.r2);
143â†’      const c1 = Math.min(selectedRange.c1, selectedRange.c2);
144â†’      const c2 = Math.max(selectedRange.c1, selectedRange.c2);
145â†’      for (let r = r1; r <= r2; r++) {
146â†’        for (let c = c1; c <= c2; c++) {
147â†’          res.push({ r, c });
148â†’        }
149â†’      }
150â†’      return res;
151â†’    }
152â†’    if (selectedCell) return [selectedCell];
153â†’    return [];
154â†’  }, [selectedCell, selectedRange]);
155â†’
156â†’  const handleCellClick = (r, c, e) => {
157â†’    if (e.shiftKey && selectedCell) {
158â†’      setSelectedRange({
159â†’        r1: selectedCell.r, c1: selectedCell.c,
160â†’        r2: r, c2: c
161â†’      });
162â†’      setSelectedCell(null);
163â†’    } else {
164â†’      setSelectedCell({ r, c });
165â†’      setSelectedRange(null);
166â†’    }
167â†’    setContextMenu(null);
168â†’    setActivePanel(null);
169â†’  };
170â†’
171â†’  const handleCellMouseDown = (r, c, e) => {
172â†’    if (e.button === 0 && !e.shiftKey) {
173â†’      setSelecting(true);
174â†’      setSelectionStart({ r, c });
175â†’    }
176â†’  };
177â†’
178â†’  const handleCellMouseEnter = (r, c) => {
179â†’    if (selecting && selectionStart) {
180â†’      setSelectedCell(null);
181â†’      setSelectedRange({
182â†’        r1: selectionStart.r, c1: selectionStart.c,
183â†’        r2: r, c2: c
184â†’      });
185â†’    }
186â†’  };
187â†’
188â†’  const handleMouseUp = () => {
189â†’    setSelecting(false);
190â†’    setSelectionStart(null);
191â†’    if (resizing) {
192â†’      setResizing(null);
193â†’      setResizeStart(null);
194â†’    }
195â†’  };
196â†’
197â†’  useEffect(() => {
198â†’    document.addEventListener('mouseup', handleMouseUp);
199â†’    return () => document.removeEventListener('mouseup', handleMouseUp);
200â†’  }, []);
201â†’
202â†’  const handleCellDoubleClick = (r, c) => {
203â†’    const cell = getCell(r, c);
204â†’    setEditValue(cell.value || '');
205â†’    setEditMode(true);
206â†’    setTimeout(() => editRef.current?.focus(), 10);
207â†’  };
208â†’
209â†’  const handleEditFinish = () => {
210â†’    if (selectedCell) {
211â†’      updateCell(selectedCell.r, selectedCell.c, { value: editValue });
212â†’    }
213â†’    setEditMode(false);
214â†’  };
215â†’
216â†’  const handleContextMenu = (r, c, e) => {
217â†’    e.preventDefault();
218â†’    setSelectedCell({ r, c });
219â†’    setSelectedRange(null);
220â†’    setContextMenu({
221â†’      x: Math.min(e.clientX, window.innerWidth - 220),
222â†’      y: Math.min(e.clientY, window.innerHeight - 300),
223â†’    });
224â†’  };
225â†’
226â†’  const handleKeyDown = (e) => {
227â†’    if (!selectedCell) return;
228â†’    if (editMode) {
229â†’      if (e.key === 'Enter' && !e.shiftKey) { handleEditFinish(); e.preventDefault(); }
230â†’      if (e.key === 'Escape') { setEditMode(false); e.preventDefault(); }
231â†’      return;
232â†’    }
233â†’    let { r, c } = selectedCell;
234â†’    if (e.key === 'ArrowUp') r = Math.max(0, r - 1);
235â†’    else if (e.key === 'ArrowDown') r = Math.min(rows - 1, r + 1);
236â†’    else if (e.key === 'ArrowLeft') c = Math.max(0, c - 1);
237â†’    else if (e.key === 'ArrowRight') c = Math.min(cols - 1, c + 1);
238â†’    else if (e.key === 'Enter') { handleCellDoubleClick(r, c); return; }
239â†’    else if (e.key === 'Delete' || e.key === 'Backspace') {
240â†’      getSelectedCells().forEach(({ r, c }) => updateCell(r, c, { value: '' }));
241â†’      return;
242â†’    } else if (e.key.length === 1 && !e.ctrlKey && !e.metaKey) {
243â†’      setEditValue(e.key);
244â†’      setEditMode(true);
245â†’      setTimeout(() => editRef.current?.focus(), 10);
246â†’      return;
247â†’    } else return;
248â†’    e.preventDefault();
249â†’    setSelectedCell({ r, c });
250â†’    setSelectedRange(null);
251â†’  };
252â†’
253â†’  // Column resize
254â†’  const handleColResizeStart = (colIdx, e) => {
255â†’    e.stopPropagation();
256â†’    e.preventDefault();
257â†’    setResizing({ type: 'col', index: colIdx });
258â†’    setResizeStart({ x: e.clientX, y: e.clientY, origSize: colWidths[colIdx] || 80 });
259â†’  };
260â†’
261â†’  // Row resize
262â†’  const handleRowResizeStart = (rowIdx, e) => {
263â†’    e.stopPropagation();
264â†’    e.preventDefault();
265â†’    setResizing({ type: 'row', index: rowIdx });
266â†’    setResizeStart({ x: e.clientX, y: e.clientY, origSize: rowHeights[rowIdx] || 36 });
267â†’  };
268â†’
269â†’  useEffect(() => {
270â†’    if (!resizing || !resizeStart) return;
271â†’    const handleMouseMove = (e) => {
272â†’      if (resizing.type === 'col') {
273â†’        const delta = e.clientX - resizeStart.x;
274â†’        const newWidth = Math.max(30, resizeStart.origSize + delta);
275â†’        setColWidths(prev => ({ ...prev, [resizing.index]: newWidth }));
276â†’      } else {
277â†’        const delta = e.clientY - resizeStart.y;
278â†’        const newHeight = Math.max(20, resizeStart.origSize + delta);
279â†’        setRowHeights(prev => ({ ...prev, [resizing.index]: newHeight }));
280â†’      }
281â†’    };
282â†’    const handleMouseUp2 = () => {
283â†’      setResizing(null);
284â†’      setResizeStart(null);
285â†’    };
286â†’    document.addEventListener('mousemove', handleMouseMove);
287â†’    document.addEventListener('mouseup', handleMouseUp2);
288â†’    return () => {
289â†’      document.removeEventListener('mousemove', handleMouseMove);
290â†’      document.removeEventListener('mouseup', handleMouseUp2);
291â†’    };
292â†’  }, [resizing, resizeStart]);
293â†’
294â†’  const applyStyleToSelection = (styleUpdate) => {
295â†’    getSelectedCells().forEach(({ r, c }) => {
296â†’      const cell = getCell(r, c);
297â†’      updateCell(r, c, { style: { ...cell.style, ...styleUpdate } });
298â†’    });
299â†’    setActivePanel(null);
300â†’    setContextMenu(null);
301â†’  };
302â†’
303â†’  const deleteCells = () => {
304â†’    getSelectedCells().forEach(({ r, c }) => updateCell(r, c, { value: '', style: {} }));
305â†’    setContextMenu(null);
306â†’  };
307â†’
308â†’  const addRow = () => setRows(prev => prev + 5);
309â†’  const removeRow = () => setRows(prev => Math.max(5, prev - 1));
310â†’  const addCol = () => setCols(prev => prev + 2);
311â†’  const removeCol = () => setCols(prev => Math.max(3, prev - 1));
312â†’
313â†’  const linkToMachine = (machineId) => {
314â†’    if (selectedCell) {
315â†’      updateCell(selectedCell.r, selectedCell.c, {
316â†’        linkedMachine: machineId,
317â†’        value: `stanok:${machineId}`,
318â†’      });
319â†’    }
320â†’    setActivePanel(null);
321â†’    setContextMenu(null);
322â†’  };
323â†’
324â†’  const unlinkMachine = () => {
325â†’    if (selectedCell) {
326â†’      updateCell(selectedCell.r, selectedCell.c, {
327â†’        linkedMachine: null,
328â†’        value: '',
329â†’      });
330â†’    }
331â†’    setContextMenu(null);
332â†’  };
333â†’
334â†’  const getCurrentShift = () => {
335â†’    const now = new Date();
336â†’    const hour = now.getHours();
337â†’    if (hour >= 7 && hour < 19) return { type: 'KUNDUZ', label: 'Kunduzgi', shift: 1 };
338â†’    return { type: 'TUN', label: 'Tungi', shift: 2 };
339â†’  };
340â†’
341â†’  const renderCellValue = (r, c) => {
342â†’    const cell = getCell(r, c);
343â†’    if (cell.linkedMachine) {
344â†’      const machine = machines.find(m => m.id === cell.linkedMachine);
345â†’      const shift = getCurrentShift();
346â†’      const meters = machine ? (machine.shift_meters || 0).toFixed(1) : '0.0';
347â†’      const statusColor = machine?.status === 'RUNNING' ? '#39ff14' : machine?.status === 'OFFLINE' ? '#ff3131' : '#ffea00';
348â†’      return (
349â†’        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '2px', lineHeight: 1.2 }}>
350â†’          <span style={{ fontSize: '0.6rem', fontWeight: 800, color: statusColor }}>{cell.linkedMachine}</span>
351â†’          <span style={{ fontSize: '0.75rem', fontWeight: 700, color: '#fff' }}>{meters}m</span>
352â†’          <span style={{ fontSize: '0.5rem', color: '#94a3b8', fontWeight: 600 }}>{shift.label}</span>
353â†’        </div>
354â†’      );
355â†’    }
356â†’    return cell.value;
357â†’  };
358â†’
359â†’  const getCellStyle = (r, c) => {
360â†’    const cell = getCell(r, c);
361â†’    const isSelected = (selectedCell && selectedCell.r === r && selectedCell.c === c) ||
362â†’      (selectedRange && r >= Math.min(selectedRange.r1, selectedRange.r2) &&
363â†’        r <= Math.max(selectedRange.r1, selectedRange.r2) &&
364â†’        c >= Math.min(selectedRange.c1, selectedRange.c2) &&
365â†’        c <= Math.max(selectedRange.c1, selectedRange.c2));
366â†’
367â†’    return {
368â†’      background: isSelected ? 'rgba(0, 210, 255, 0.15)' : (cell.style?.background || 'transparent'),
369â†’      border: isSelected ? '2px solid var(--primary)' : '1px solid rgba(255,255,255,0.06)',
370â†’      color: cell.style?.color || '#f8fafc',
371â†’      fontWeight: cell.style?.fontWeight || 400,
372â†’      fontStyle: cell.style?.fontStyle || 'normal',
373â†’      textDecoration: cell.style?.textDecoration || 'none',
374â†’      fontSize: cell.style?.fontSize ? `${cell.style.fontSize}px` : '0.8rem',
375â†’      fontFamily: cell.style?.fontFamily || 'Inter',
376â†’      textAlign: cell.style?.textAlign || 'center',
377â†’    };
378â†’  };
379â†’
380â†’  const handleSave = () => {
381â†’    const data = { rows, cols, cells, title, colWidths, rowHeights };
382â†’    if (onSave) onSave(data);
383â†’  };
384â†’
385â†’  const handleExportPDF = () => {
386â†’    if (onSave) onSave({ rows, cols, cells, title, colWidths, rowHeights, exportPDF: true });
387â†’  };
388â†’
389â†’  return (
390â†’    <div
391â†’      style={{ display: 'flex', flexDirection: 'column', height: '100%', position: 'relative' }}
392â†’      onKeyDown={handleKeyDown}
393â†’      tabIndex={0}
394â†’    >
395â†’      {/* Toolbar */}
396â†’      <div style={{
397â†’        display: 'flex', alignItems: 'center', gap: '6px', padding: '8px 12px',
398â†’        background: 'rgba(15,23,42,0.8)', borderBottom: '1px solid rgba(255,255,255,0.08)',
399â†’        flexWrap: 'wrap', flexShrink: 0
400â†’      }}>
401â†’        <input
402â†’          value={title}
403â†’          onChange={e => setTitle(e.target.value)}
404â†’          style={{
405â†’            background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)',
406â†’            borderRadius: '8px', padding: '6px 12px', color: '#f8fafc', fontSize: '0.9rem',
407â†’            fontWeight: 700, outline: 'none', width: '200px'
408â†’          }}
409â†’          placeholder="Sarlavha"
410â†’        />
411â†’
412â†’        <div style={{ width: '1px', height: '24px', background: 'rgba(255,255,255,0.1)', margin: '0 4px' }} />
413â†’
414â†’        <ToolBtn icon={<Plus size={14} />} onClick={addRow} title="Qator qo'shish" />
415â†’        <ToolBtn icon={<Minus size={14} />} onClick={removeRow} title="Qator olib tashlash" />
416â†’        <ToolBtn icon={<Plus size={14} />} onClick={addCol} title="Ustun qo'shish" label="U" />
417â†’        <ToolBtn icon={<Minus size={14} />} onClick={removeCol} title="Ustun olib tashlash" label="U" />
418â†’
419â†’        <div style={{ width: '1px', height: '24px', background: 'rgba(255,255,255,0.1)', margin: '0 4px' }} />
420â†’
421â†’        {/* Matn joylashuvi tugmalari */}
422â†’        <ToolBtn icon={<AlignLeft size={14} />} onClick={() => applyStyleToSelection({ textAlign: 'left' })} title="Chapga" />
423â†’        <ToolBtn icon={<AlignCenter size={14} />} onClick={() => applyStyleToSelection({ textAlign: 'center' })} title="Markazga" />
424â†’        <ToolBtn icon={<AlignRight size={14} />} onClick={() => applyStyleToSelection({ textAlign: 'right' })} title="O'ngga" />
425â†’
426â†’        <div style={{ width: '1px', height: '24px', background: 'rgba(255,255,255,0.1)', margin: '0 4px' }} />
427â†’
428â†’        {/* Avto kengayish tugmasi */}
429â†’        <ToolBtn
430â†’          icon={autoResize ? <Shrink size={14} /> : <Expand size={14} />}
431â†’          onClick={() => {
432â†’            const newState = !autoResize;
433â†’            setAutoResize(newState);
434â†’            if (newState) autoResizeAll();
435â†’          }}
436â†’          title={autoResize ? "Avto kengayishni o'chirish" : "Avto kengayishni yoqish"}
437â†’          label={autoResize ? 'Auto ON' : 'Auto OFF'}
438â†’          active={autoResize}
439â†’          color={autoResize ? '#39ff14' : undefined}
440â†’        />
441â†’
442â†’        <div style={{ width: '1px', height: '24px', background: 'rgba(255,255,255,0.1)', margin: '0 4px' }} />
443â†’
444â†’        <ToolBtn icon={<Palette size={14} />} onClick={() => setActivePanel(activePanel === 'color' ? null : 'color')} title="Rang" active={activePanel === 'color'} />
445â†’        <ToolBtn icon={<Type size={14} />} onClick={() => setActivePanel(activePanel === 'font' ? null : 'font')} title="Shrift" active={activePanel === 'font'} />
446â†’        <ToolBtn icon={<Link2 size={14} />} onClick={() => setActivePanel(activePanel === 'machine' ? null : 'machine')} title="Stanok bog'lash" active={activePanel === 'machine'} />
447â†’        <ToolBtn icon={<Trash2 size={14} />} onClick={deleteCells} title="O'chirish" />
448â†’
449â†’        <div style={{ flex: 1 }} />
450â†’
